import{_ as t,o,c as d,a2 as r}from"./chunks/framework.ChXBHUFc.js";const m=JSON.parse('{"title":"BLE protocol","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ble-protocol.md","filePath":"guide/ble-protocol.md","lastUpdated":1782645856000}'),a={name:"guide/ble-protocol.md"};function s(c,e,n,i,l,p){return o(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="ble-protocol" tabindex="-1">BLE protocol <a class="header-anchor" href="#ble-protocol" aria-label="Permalink to &quot;BLE protocol&quot;">​</a></h1><p>Notes on the Triki BLE interface, captured with <a href="./tooling">bleak</a> on macOS.</p><blockquote><p><strong>OPSEC:</strong> device-identifying values (chip ID, any per-device value) are NOT recorded here — only structure is kept.</p></blockquote><h2 id="advertising" tabindex="-1">Advertising <a class="header-anchor" href="#advertising" aria-label="Permalink to &quot;Advertising&quot;">​</a></h2><p>Name <code>TRIKI &lt;serial&gt;</code> / <code>Triki &lt;serial&gt;</code>, address <code>XX:XX:XX:XX:XX:XX</code> (random static), service <code>0x0001</code>.</p><h2 id="gatt" tabindex="-1">GATT <a class="header-anchor" href="#gatt" aria-label="Permalink to &quot;GATT&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nordic UART Service  6e400001-b5a3-f393-e0a9-e50e24dcca9e</span></span>
<span class="line"><span>  RX   …0002  [write, write-no-response]   commands host -&gt; token</span></span>
<span class="line"><span>  TX   …0003  [notify]                     responses token -&gt; host</span></span>
<span class="line"><span>  ctrl …0004  [read, write]                control register</span></span>
<span class="line"><span>Battery 0x180F → 0x2A19 (Battery Level)</span></span></code></pre></div><p>The token speaks a <strong>request/response protocol over NUS</strong>: TX stays silent until a command arrives on RX.</p><h2 id="device-information-service-0x180a" tabindex="-1">Device Information Service (<code>0x180A</code>) <a class="header-anchor" href="#device-information-service-0x180a" aria-label="Permalink to &quot;Device Information Service (\`0x180A\`)&quot;">​</a></h2><p>Besides the NUS, the token also exposes the standard <strong>Generic Access</strong> (<code>0x1800</code>) and <strong>Device Information</strong> (<code>0x180A</code>) services. An independent reader (<a href="https://github.com/AND-Y0/TrikiReader" target="_blank" rel="noreferrer">TrikiReader</a>) reads the full set below; confirm per-device with <a href="./tooling"><code>tools/ble_dump.py</code></a> before relying on any one field — not every unit necessarily populates all of them.</p><table tabindex="0"><thead><tr><th>Characteristic</th><th>UUID</th><th>Notes</th></tr></thead><tbody><tr><td>Device Name</td><td><code>0x2A00</code> (on <code>0x1800</code>)</td><td><code>Triki &lt;serial&gt;</code></td></tr><tr><td>Manufacturer Name</td><td><code>0x2A29</code></td><td>string</td></tr><tr><td>Model Number</td><td><code>0x2A24</code></td><td>string</td></tr><tr><td>Firmware Revision</td><td><code>0x2A26</code></td><td>version string (e.g. <code>X.Y.Z</code>)</td></tr><tr><td>Hardware Revision</td><td><code>0x2A27</code></td><td>string</td></tr><tr><td>Software Revision</td><td><code>0x2A28</code></td><td>string</td></tr><tr><td>Serial Number</td><td><code>0x2A25</code></td><td>per-device — <strong>not recorded here</strong></td></tr><tr><td>System ID</td><td><code>0x2A23</code></td><td>8-byte, per-device — <strong>not recorded here</strong></td></tr><tr><td>PnP ID</td><td><code>0x2A50</code></td><td>source + vendor / product / version IDs</td></tr></tbody></table><p><code>PnP ID</code> (<code>0x2A50</code>) is the standard 7-byte record <code>[source][vendorId LE][productId LE][versionId LE]</code>, where source <code>0x01</code> = Bluetooth SIG, <code>0x02</code> = USB — a potential lead on the vendor/product identity.</p><blockquote><p><strong>OPSEC:</strong> Serial Number, System ID and the advertised <code>&lt;serial&gt;</code> are per-device identifiers — keep them out of tracked files (use placeholders <code>&lt;serial&gt;</code> / <code>XX:XX:XX:XX:XX:XX</code>).</p></blockquote><h2 id="control-register-0x0004-—-green-led" tabindex="-1">Control register 0x0004 — green LED <a class="header-anchor" href="#control-register-0x0004-—-green-led" aria-label="Permalink to &quot;Control register 0x0004 — green LED&quot;">​</a></h2><ul><li><strong>1-bit flag.</strong> Writes saturate: <code>0x00</code> → reads back <code>0x00</code>; any value <code>&gt;= 0x01</code> → reads back <code>0x01</code>. Effective search space = 2 states.</li><li><strong>Bit0 directly drives the green LED</strong>: <code>0x01</code> = green on, <code>0x00</code> = off — immediate, no timeout (confirmed visually).</li></ul><h2 id="rx-0x0002-—-command-interface" tabindex="-1">RX 0x0002 — command interface <a class="header-anchor" href="#rx-0x0002-—-command-interface" aria-label="Permalink to &quot;RX 0x0002 — command interface&quot;">​</a></h2><ul><li>Commands are <strong>byte sequences</strong> (byte0 = opcode). Some are single-byte, some are multi-byte (e.g. the 8-byte IMU start command — see <a href="./imu-streaming">IMU streaming</a>).</li><li><strong>Response opcode = request opcode | 0x80</strong> (bit7 set = &quot;this is a reply&quot;), delivered on TX as one or more 20-byte notification packets.</li><li>A few opcodes reboot the device (short LED blink, link drops, comes back as the same device — a soft reset).</li></ul><h3 id="opcode-map-rx-→-tx-so-far" tabindex="-1">Opcode map (RX → TX), so far <a class="header-anchor" href="#opcode-map-rx-→-tx-so-far" aria-label="Permalink to &quot;Opcode map (RX → TX), so far&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Opcode</th><th>Reply</th><th>Meaning / notes</th></tr></thead><tbody><tr><td><code>0x05</code></td><td><code>85</code> + 12 bytes</td><td><strong>static</strong> config/status — does NOT change with motion</td></tr><tr><td><code>0x07</code></td><td><code>87</code> + 8 bytes</td><td>device unique ID — stable across reads; value redacted</td></tr><tr><td><code>0x09</code></td><td><code>89</code> + ~54 bytes (multi-packet)</td><td>status block — counter + state fields; NOT motion data</td></tr><tr><td><code>0x0c</code></td><td><code>8c 01 00 00 00</code></td><td>short status/counter</td></tr><tr><td><code>0x43</code></td><td><code>c3</code> + ~54 bytes</td><td>changes every read → live buffer/counter; value redacted</td></tr><tr><td><code>0x0a</code>, <code>0x42</code>, <code>0x44</code>, <code>0x46</code></td><td>—</td><td>reboot (soft reset)</td></tr><tr><td>all other <code>0x00</code>–<code>0x7f</code></td><td>—</td><td>silent (no single-byte reply; likely need parameters)</td></tr></tbody></table><p>The raw IMU is <strong>not</strong> on these single-byte opcodes — it comes from the dedicated start-stream command on the <a href="./imu-streaming">IMU streaming</a> page.</p><h2 id="sample-rate-odr" tabindex="-1">Sample rate (ODR) <a class="header-anchor" href="#sample-rate-odr" aria-label="Permalink to &quot;Sample rate (ODR)&quot;">​</a></h2><p>The 8-byte IMU start command (<code>20 10 00 D0 07 68 00 03</code>, see <a href="./imu-streaming">IMU streaming</a>) carries the sample rate in <strong>bytes 5–6</strong> (little-endian uint16, in Hz):</p><ul><li><code>68 00</code> = <code>0x0068</code> = <strong>104 Hz</strong> — the default.</li><li>The firmware accepts the LSM6DSL ODR steps <strong>26 / 52 / 104 / 208 / 416 Hz</strong> (exposed as 0.25× … 4× in the web controller). <code>12.5 Hz</code> is rejected.</li><li>Above ~208 Hz BLE often can&#39;t keep up — watch the actual <em>streaming N Hz</em> reported by the controller rather than the requested rate.</li><li>Bytes 3–4 (<code>D0 07</code> = 2000) and byte 7 (<code>03</code>) are a fixed, <strong>not-yet-decoded</strong> part of the command — they are not the rate; leave them as-is.</li></ul>`,23)])])}const g=t(a,[["render",s]]);export{m as __pageData,g as default};
